-- ---------------------------------------------------------- Tabel structuur voor tabel dagentabel-- --------------------------------------------------------DROP TABLE IF EXISTS dagentabel;CREATE TABLE dagentabel (persoon_id smallint(11) NOT NULL,krediet decimal(8,0) NOT NULL default '0',-- in eurocentenstartdatum date NOT NULL default '0000-00-00',strategie smallint(4) default '0',-- 0=opstart 1=abstin 2=controlpersonalmax smallint(4) default '0',date_lastlogin date default NULL,eerste_probleem  smallint(4) default '',tweede_probleem  smallint(4) default '',berekend_probleem  smallint(4) default '',-- 1-ontspanning/ 2 slaapstoringen/ 3 neurotisch (eisen > mogelijkheden) / 4 het gevoel van (emotionele of fysieke) pijn verdoven / 5 de herinneringen aan een traumatische gebeurtenis blokkeren / 6 het gevoel van eenzaamheid en/of leegte invullen / 7 een gebrek aan kicks in mijn leven / 8 zelfmedicatie bij ADHD / 9 zelfmedicatie bij depressie /10 0zelfmedicatie bij (sociale) angsten / 11 zelfmedicatie bij een paniekstoornis/hyperventilatie / 12 de moed verzamelen om verborgen stukken van mijzelf uit te leven / 13 Om onhoudbare leefsituaties uit te houdeneerste_middel  smallint(4) default '',tweede_middel  smallint(4) default '',PRIMARY KEY (persoon_id),KEY krediet (krediet)) TYPE=MyISAM;-- Gegevens worden uitgevoerd voor tabel dagentabelINSERT INTO dagentabel VALUES (0, 100, '2006-07-01', 0, 3, '2009-01-02', 1, 2, 3, 2, 1,1);